//-----------------------------------------------------------------------------
// MRFPitchAssy : destructor
//-----------------------------------------------------------------------------
MRFPitchAssy::~MRFPitchAssy()
{
	if (_DescOfPitchSeq.GetLengthInChar() > 0) 
		_DescOfPitchSeq.Reset();

	if (_InputMRFPitchAssyName.GetLengthInChar() > 0) 
		_InputMRFPitchAssyName.Reset();

	if (_ListOfPitches.Size() > 0)
		_ListOfPitches.RemoveAll();

	if (NULL != _pPathSelectedAssy)
		_pPathSelectedAssy->Release();
		_pPathSelectedAssy = NULL;

	if (NULL != _pAssyProdRef)
		_pAssyProdRef->Release();
		_pAssyProdRef = NULL;

	if (_iListIndex.Size() > 0)
		_iListIndex.RemoveAll();

	if (_ListOfUnchangedInstances.Size() > 0)
		_ListOfUnchangedInstances.RemoveAll();

	if (_ListOfInstancesToDelete.Size() > 0)
		_ListOfInstancesToDelete.RemoveAll();

	if (NULL_var != _pAssyNavOccurence)
		_pAssyNavOccurence = NULL_var;

	if (_ListOfGeometricalSets.Size() > 0)
		_ListOfGeometricalSets.RemoveAll();
}

