//-----------------------------------------------------------------------------
// MRFPitchAssy : Initialize
// Function: create product reference, create 3DPart
//-----------------------------------------------------------------------------
void MRFPitchAssy::Init()
{
	HRESULT rc = E_FAIL;
	if (NULL == _pAssyProdRef)
	{
		if (!MRFProdStrServices::ScanIfProdRefExists(_InputMRFPitchAssyName))
		{
			if (0 == _MRFAssyType)
				rc = MRFProdStrServices::CreateProdReference(_InputMRFPitchAssyName);
			else if (1 == _MRFAssyType)
				rc = MRFProdStrServices::Create3DPart(_InputMRFPitchAssyName);

			if (SUCCEEDED(rc))
			{
				_pAssyProdRef = MRFProdStrServices::GetProductRefFromName(_InputMRFPitchAssyName);
				if (NULL != _pAssyProdRef)
				{
					_pAssyProdRef->AddRef();
					MRFProdStrServices::SetInstanceName(_pAssyProdRef, _InputMRFPitchAssyName);
					_bExistingAssy = CATFalse;
				}
			}
		}
		else
		{
			_pAssyProdRef = MRFProdStrServices::GetProductRefFromName(_InputMRFPitchAssyName);
			if (NULL != _pAssyProdRef)
			{
				_pAssyProdRef->AddRef();
				_bExistingAssy = CATTrue;
			}
		}
	}
	SetAssyPathElement();
}

//-----------------------------------------------------------------------------
// MRFPitchAssy : SetAssyPathElement
// Function: set assembly path element
//-----------------------------------------------------------------------------
void MRFPitchAssy::SetAssyPathElement()
{
	if (NULL != _pAssyProdRef)
	{
		CATIPLMNavInstance * hNavInst = NULL;
		if (SUCCEEDED(_pAssyProdRef->QueryInterface(IID_CATIPLMNavInstance, (void**)&hNavInst)) && NULL_var != hNavInst)
		{
			CATIPLMNavReference *piPLMNavRef = NULL;
			HRESULT rc = hNavInst->GetReferenceInstanceOf(piPLMNavRef);
			if (SUCCEEDED(rc) && NULL != piPLMNavRef)
			{
				CATIPLMNavOccurrence *pNavOccurenceObj = NULL;
				hNavInst->GetFirstLevelOccurrence(pNavOccurenceObj, pNavOccurenceObj);
				if (NULL != pNavOccurenceObj)
				{
					_pAssyNavOccurence = pNavOccurenceObj;
					CATFrmEditor * pEditor = CATFrmEditor::GetCurrentEditor();
					if (NULL != pEditor)
					{
						CATPathElement pathElmnt = pEditor->GetUIActiveObject();

						_pPathSelectedAssy = new CATPathElement(pathElmnt);
						_pPathSelectedAssy->AddChildElement(pNavOccurenceObj);
					}
					pNavOccurenceObj->Release();
					pNavOccurenceObj = NULL;
				}
				piPLMNavRef->Release();
				piPLMNavRef = NULL;
			}
			hNavInst->Release();
			hNavInst=NULL;
		}
	}
}

