//-----------------------------------------------------------------------------
// MRFPitchAssy : AssignPitchSequence
//-----------------------------------------------------------------------------
void MRFPitchAssy::SetPitchSequence(const CATUnicodeString iDescOfPitchSeq, bool _isPitchSeqOrAngChanged)
{
	_DescOfPitchSeq = iDescOfPitchSeq;

	//CATBaseUnknown * AssyRefPRD = MRFProdStrServices::GetProductRefFromName(_InputMRFPitchAssyName);
	if (NULL != _pAssyProdRef)
	{
		if (_bExistingAssy)
		{
			stringstream strCurrentStream(iDescOfPitchSeq.ConvertToChar());
			string line = "";
			const char delim = ',';
			CATListOfCATUnicodeString ListCurrentSequence, ListOldSequence;
			while (getline(strCurrentStream, line, delim))
			{
				if (!line.empty())
				{
					ListCurrentSequence.Append(line.c_str());
				}
			}

			CATUnicodeString iExistingPitchSeq;
			MRFProdStrServices::GetDescFromProdRef(_pAssyProdRef, iExistingPitchSeq);
			if (iExistingPitchSeq.Compare(iDescOfPitchSeq) != 2)
			{
				stringstream strOldStream(iExistingPitchSeq.ConvertToChar());
				// Iterate through each line and split the content using delimeter
				line = "";
				while (getline(strOldStream, line, delim))
				{
					if (!line.empty())
					{
						ListOldSequence.Append(line.c_str());
					}
				}

				
				if (_isPitchSeqOrAngChanged)
				{
					CATListOfInt visitedPitchIndex;
					for (int i = 1; i <= ListCurrentSequence.Size(); i++)
					{
						bool seqFound = false;

						for (int j = 1; j <= ListOldSequence.Size(); j++)
						{
							if (ListCurrentSequence[i] == ListOldSequence[j] && !visitedPitchIndex.Locate(j))
							{								
								visitedPitchIndex.Append(j);
								seqFound = true;
								break;
							}
						}
					}

					_ListOfVisitedInstancesOnlyForSeqChange = visitedPitchIndex;
				}
					

				int i = 1;
				//for (int i = 0; i <= strHigherSeq.GetLengthInChar(); i++)
				while ( i <= ListCurrentSequence.Size() && i <= ListOldSequence.Size() )
				{
					if (ListCurrentSequence[i].Compare(ListOldSequence[i]) != 2)
					{
						_iListIndex.Append(i);
					}
					else
					{
						_ListOfUnchangedInstances.Append(i);
					}
					i++;
				}				
				if (ListCurrentSequence.Size() < ListOldSequence.Size())
				{
					for (int j = ListCurrentSequence.Size()+1; j <= ListOldSequence.Size(); j++)
					{
						_ListOfInstancesToDelete.Append(j);
					}
				}
			}
			else
			{
				int i = 1;
				while ( i <= ListCurrentSequence.Size() )
				{
					_ListOfUnchangedInstances.Append(i);
					i++;
				}
			}
		}
		MRFProdStrServices::SetDescToProdRef(_pAssyProdRef, _DescOfPitchSeq);
	}
}

