//-----------------------------------------------------------------------------
// MRFPitchAssy : CreateGeomSets
//-----------------------------------------------------------------------------
void MRFPitchAssy::CreateGeomSets(CATListOfCATUnicodeString iListOfGeomSetName)
{
	CATListOfCATUnicodeString iListOfGeomSetNameToDelete;
	HRESULT hr = E_FAIL;
	if (NULL != _pAssyProdRef)
	{
		CATIPLMNavInstance * hNavInst = NULL;
		hr = _pAssyProdRef->QueryInterface(IID_CATIPLMNavInstance, (void**)&hNavInst);
		if (SUCCEEDED(hr) && NULL_var != hNavInst)
		{
			CATListOfCATUnicodeString iListOfGeomSetNamesNotToCreate;

			CATIPartRequest * pPartRequest = NULL;
			hr = MRFProdStrServices::GetPartRequestFromInstance(hNavInst, pPartRequest);

			if (SUCCEEDED(hr) && NULL != pPartRequest)
			{
				CATListValCATBaseUnknown_var oGeomSets;
				if (SUCCEEDED(pPartRequest->GetSurfBodies("MfDefault3DView", oGeomSets)) && oGeomSets.Size() > 0)
				{
					for (int iG = 1; iG <= oGeomSets.Size(); iG++)
					{
						CATIAlias_var spAlias = oGeomSets[iG];
						CATUnicodeString strAlias = spAlias->GetAlias();
						if (iListOfGeomSetName.Locate(strAlias) > 0)
						{
							CATIMmiMechanicalFeature_var hGSFeature;
							if (SUCCEEDED(oGeomSets[iG]->QueryInterface(IID_CATIMmiMechanicalFeature, (void**)&hGSFeature)) && NULL_var != hGSFeature)
							{
								_ListOfGeometricalSets.Append(hGSFeature);

								//DeleteExistingFeatures(hGSFeature);
							}
														
							iListOfGeomSetNamesNotToCreate.Append(strAlias);
						}
						else
						{
							if (!strAlias.Compare("Back Profile Surface GeomSet") && !strAlias.Compare("CircumferenceGeomSet"))
								iListOfGeomSetNameToDelete.Append(strAlias);
						}
					}
				}


				CATIMmiMechanicalFeature * spMechFeatOnPart = NULL;
				hr = pPartRequest->QueryInterface(IID_CATIMmiMechanicalFeature, (void**)&spMechFeatOnPart);
				if (SUCCEEDED(hr) && NULL != spMechFeatOnPart)
				{
					CATIMmiUsePrtPart_var spMmiUsePrtPart = spMechFeatOnPart;
					if (SUCCEEDED(hr) && NULL_var != spMmiUsePrtPart)
					{
						for (int i = 1; i <= iListOfGeomSetName.Size(); i++)
						{
							CATUnicodeString iGSName = iListOfGeomSetName[i];
							if ((iListOfGeomSetNamesNotToCreate.Locate(iGSName) == 0 || iListOfGeomSetNamesNotToCreate.Size() == 0) && iGSName.GetLengthInChar() > 0)
							{
								CATIGSMTool* pGSMTool = NULL;
								MRFGenericUtils::CreateGSMTool(spMmiUsePrtPart, pGSMTool, TRUE, iGSName);//TRUE added to created Ordered Geometrical Set
								if (NULL != pGSMTool)
								{
									CATIMmiMechanicalFeature_var hGSFeature;
									if (SUCCEEDED(pGSMTool->QueryInterface(IID_CATIMmiMechanicalFeature, (void**)&hGSFeature)) && NULL_var != hGSFeature)
									{
										_ListOfGeometricalSets.Append(hGSFeature);
									}
									pGSMTool->Release();
									pGSMTool = NULL;
								}
							}
						}
					}
					spMechFeatOnPart->Release();
					spMechFeatOnPart = NULL;
				}
				//pPartRequest->Release();
				//pPartRequest = NULL;
			}

			if (NULL != pPartRequest)
			{
				MRFGenericUtils::DeleteGSMTool(pPartRequest, iListOfGeomSetNameToDelete);

				pPartRequest->Release();
				pPartRequest = NULL;
			}


			hNavInst->Release();
			hNavInst = NULL;
		}

	}
}

